        ST(&rio_re[(m+16)+1*ios], c_x1_re);
        ST(&rio_im[(m+16)+1*ios], c_x1_im);
        ST(&rio_re[(m+16)+2*ios], c_x2_re);
        ST(&rio_im[(m+16)+2*ios], c_x2_im);
