        c_x0_re=_mm512_add_pd(c_x0_re,ar); c_x0_im=_mm512_add_pd(c_x0_im,ai);
        c_x2_re=_mm512_fmadd_pd(KS,di,R1r); c_x2_im=_mm512_fnmadd_pd(KS,dr,R1i);
