        b_x1_re = LD(&rio_re[(m+8)+1*ios]);
        b_x1_im = LD(&rio_im[(m+8)+1*ios]);
        b_x2_re = LD(&rio_re[(m+8)+2*ios]);
        b_x2_im = LD(&rio_im[(m+8)+2*ios]);
        { const __m512d b_tr = b_x1_re;
          b_x1_re = _mm512_fmsub_pd(b_x1_re,tw0_re,_mm512_mul_pd(b_x1_im,tw0_im));
          b_x1_im = _mm512_fmadd_pd(b_tr,tw0_im,_mm512_mul_pd(b_x1_im,tw0_re)); }
        { const __m512d b_tr = b_x2_re;
          b_x2_re = _mm512_fmsub_pd(b_x2_re,tw1_re,_mm512_mul_pd(b_x2_im,tw1_im));
          b_x2_im = _mm512_fmadd_pd(b_tr,tw1_im,_mm512_mul_pd(b_x2_im,tw1_re)); }

