        w2i = _mm512_fmadd_pd(w1r,w1i,_mm512_mul_pd(w1i,w1r));

        a_x0_re = LD(&rio_re[m+0*ios]);
        a_x0_im = LD(&rio_im[m+0*ios]);
        a_x1_re = LD(&rio_re[m+1*ios]);
        a_x1_im = LD(&rio_im[m+1*ios]);
        a_x2_re = LD(&rio_re[m+2*ios]);
        a_x2_im = LD(&rio_im[m+2*ios]);
        { __m512d a_tr = a_x1_re;
          a_x1_re = _mm512_fmsub_pd(a_x1_re,w1r,_mm512_mul_pd(a_x1_im,w1i));
          a_x1_im = _mm512_fmadd_pd(a_tr,w1i,_mm512_mul_pd(a_x1_im,w1r)); }
        { __m512d a_tr = a_x2_re;
          a_x2_re = _mm512_fmsub_pd(a_x2_re,w2r,_mm512_mul_pd(a_x2_im,w2i));
          a_x2_im = _mm512_fmadd_pd(a_tr,w2i,_mm512_mul_pd(a_x2_im,w2r)); }

        /* DFT-3 butterfly [fwd] */
        __m512d ar=_mm512_add_pd(a_x1_re,a_x2_re), ai=_mm512_add_pd(a_x1_im,a_x2_im);
        __m512d dr=_mm512_sub_pd(a_x1_re,a_x2_re), di=_mm512_sub_pd(a_x1_im,a_x2_im);
        __m512d R1r=_mm512_fnmadd_pd(KHALF,ar,a_x0_re), R1i=_mm512_fnmadd_pd(KHALF,ai,a_x0_im);
        a_x0_re=_mm512_add_pd(a_x0_re,ar); a_x0_im=_mm512_add_pd(a_x0_im,ai);
        a_x1_re=_mm512_fmadd_pd(KS,di,R1r); a_x1_im=_mm512_fnmadd_pd(KS,dr,R1i);
        a_x2_re=_mm512_fnmadd_pd(KS,di,R1r); a_x2_im=_mm512_fmadd_pd(KS,dr,R1i);

        ST(&rio_re[m+0*ios], a_x0_re);
        ST(&rio_im[m+0*ios], a_x0_im);
        ST(&rio_re[m+1*ios], a_x1_re);
        ST(&rio_im[m+1*ios], a_x1_im);
