        x2_re=_mm512_fnmadd_pd(KS,di,R1r); x2_im=_mm512_fmadd_pd(KS,dr,R1i);

        ST(&rio_re[m+0*ios], x0_re);
        ST(&rio_im[m+0*ios], x0_im);
        ST(&rio_re[m+1*ios], x1_re);
