        __m512d ar=_mm512_add_pd(b_x1_re,b_x2_re), ai=_mm512_add_pd(b_x1_im,b_x2_im);
        __m512d dr=_mm512_sub_pd(b_x1_re,b_x2_re), di=_mm512_sub_pd(b_x1_im,b_x2_im);
        __m512d R1r=_mm512_fnmadd_pd(KHALF,ar,b_x0_re), R1i=_mm512_fnmadd_pd(KHALF,ai,b_x0_im);
        b_x0_re=_mm512_add_pd(b_x0_re,ar); b_x0_im=_mm512_add_pd(b_x0_im,ai);
        b_x2_re=_mm512_fmadd_pd(KS,di,R1r); b_x2_im=_mm512_fnmadd_pd(KS,dr,R1i);
        b_x1_re=_mm512_fnmadd_pd(KS,di,R1r); b_x1_im=_mm512_fmadd_pd(KS,dr,R1i);

        ST(&rio_re[(m+8)+0*ios], b_x0_re);
        ST(&rio_im[(m+8)+0*ios], b_x0_im);
        ST(&rio_re[(m+8)+1*ios], b_x1_re);
        ST(&rio_im[(m+8)+1*ios], b_x1_im);
        ST(&rio_re[(m+8)+2*ios], b_x2_re);
        ST(&rio_im[(m+8)+2*ios], b_x2_im);
